srcDoc.css:
* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: Inter, system-ui, sans-serif;
  background: transparent;
  font-size: 13px;
}

#notes-wrap {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

#notes-list {
  display: flex;
  flex-direction: column;
  gap: 6px;
  max-height: 320px;
  overflow-y: auto;
}

.note {
  background: #F9FAFB;
  border-radius: 6px;
  padding: 10px 12px;
  border-left: 3px solid #E5E7EB;
}

.note.status_change {
  background: #EAF3DE;
  border-left-color: #C0DD97;
}

.note.compliance {
  background: #E6F1FB;
  border-left-color: #93C5FD;
}

.note.issue {
  background: #FCEBEB;
  border-left-color: #FCA5A5;
}

.note.action {
  background: #FAEEDA;
  border-left-color: #F0C97A;
}

.note-meta {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 10px;
  color: #9CA3AF;
  margin-bottom: 4px;
}

.note-author {
  color: #1A5C3A;
  font-weight: 600;
}

.note-tag {
  padding: 1px 7px;
  border-radius: 20px;
  font-size: 9px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

.tag-status_change {
  background: #EAF3DE;
  color: #27500A;
}

.tag-compliance {
  background: #E6F1FB;
  color: #185FA5;
}

.tag-issue {
  background: #FCEBEB;
  color: #A32D2D;
}

.tag-action {
  background: #FAEEDA;
  color: #854F0B;
}

.tag-general {
  display: none;
}

.note-text {
  font-size: 12px;
  color: #1A1A2E;
  line-height: 1.5;
}

.system-badge {
  font-size: 9px;
  color: #9CA3AF;
  font-style: italic;
}

.empty {
  font-size: 12px;
  color: #9CA3AF;
  font-style: italic;
  padding: 8px 0;
  text-align: center;
}

.input-area {
  border-top: 1px solid #F3F4F6;
  padding-top: 12px;
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.type-row select {
  font-family: inherit;
  font-size: 11px;
  color: #6B7280;
  background: #F9FAFB;
  border: 1.5px solid #E5E7EB;
  border-radius: 5px;
  padding: 4px 8px;
  outline: none;
  cursor: pointer;
}

.input-row {
  display: flex;
  gap: 8px;
  align-items: flex-end;
}

textarea {
  flex: 1;
  font-family: inherit;
  font-size: 12px;
  color: #1A1A2E;
  background: #FFFFFF;
  border: 1.5px solid #E5E7EB;
  border-radius: 6px;
  padding: 8px 10px;
  outline: none;
  resize: none;
  transition: border-color 0.15s;
  line-height: 1.5;
}

textarea:focus {
  border-color: #1A5C3A;
  box-shadow: 0 0 0 3px rgba(26, 92, 58, 0.08);
}

textarea::placeholder {
  color: #9CA3AF;
}

#add-btn {
  background: #1A5C3A;
  color: #fff;
  border: none;
  border-radius: 6px;
  padding: 8px 14px;
  font-size: 12px;
  font-weight: 600;
  font-family: inherit;
  cursor: pointer;
  white-space: nowrap;
  flex-shrink: 0;
  transition: opacity 0.15s;
}

#add-btn:hover {
  opacity: 0.9;
}

#add-btn:disabled {
  background: #9CA3AF;
  cursor: not-allowed;
}

