appsmith.onReady(function () {
  render();
});
appsmith.onModelChange(function () {
  render();
});
function render() {
  var notes = appsmith.model.notes || [];
  var list = document.getElementById('notes-list');
  list.innerHTML = '';
  if (!notes.length) {
    list.innerHTML = '<div class="empty">No notes yet</div>';
    return;
  }
  notes.forEach(function (n) {
    var type = n.note_type || 'general';
    var isSystem = n.is_system;
    var tag = type !== 'general' ? '<span class="note-tag tag-' + type + '">' + type.replace('_', ' ') + '</span>' : '';
    var systemBadge = isSystem ? '<span class="system-badge">· auto-logged</span>' : '';
    var div = document.createElement('div');
    div.className = 'note ' + type;
    div.innerHTML = '<div class="note-meta">' + '<span class="note-author">' + (n.created_by || 'System') + '</span>' + tag + systemBadge + '<span style="margin-left:auto">' + (n.created_at || '') + '</span>' + '</div>' + '<div class="note-text">' + (n.note_text || '') + '</div>';
    list.appendChild(div);
  });
  list.scrollTop = list.scrollHeight;
}
function addNote() {
  var input = document.getElementById('note-input');
  var type = document.getElementById('note-type');
  var btn = document.getElementById('add-btn');
  var text = input.value.trim();
  if (!text) {
    input.focus();
    return;
  }
  btn.disabled = true;
  btn.textContent = 'Adding...';
  appsmith.triggerEvent('onAddNote', {
    noteText: text,
    noteType: type.value
  });
  input.value = '';
  type.value = 'general';
  btn.disabled = false;
  btn.textContent = 'Add';
}

